example.contents:
http {
  {{ augment_includes "http" . }}

  upstream backend {
    {{- range .upstream_servers }}
    server {{ . }};
    {{- end }}
  }

  server {
    listen 80;
    server_name {{ .server_name }};

    location / {
      proxy_pass {{ default "http://backend" .proxy_pass }};
    }
  }
}
